class StaffService{async _api(a,t={}){return window.Utils&&"function"==typeof window.Utils.callApi?await window.Utils.callApi(a,t):{status:"error",message:"Lỗi hệ thống"}}async getAll(){return await this._api("fetch_all_staff")}async create(a){return await this._api("create_staff",a)}async update(a){return await this._api("update_staff",a)}async delete(a){return await this._api("delete_staff",{id:a})}async getRoles(){return await this._api("fetch_roles")}async getManagers(){return await this._api("fetch_managers_for_select")}async getAvailableUsers(){return await this._api("fetch_available_users")}async getMembersByDept(a){return await this._api("fetch_dept_members",{id:a})}}export default new StaffService;